<script>
function showError(message){document.getElementById('tool-error-text').textContent=message;document.getElementById('tool-error').style.display='flex';document.getElementById('tool-result').classList.remove('show');}
function clearError(){document.getElementById('tool-error').style.display='none';}
function toMinutes(value){const horas=Math.floor(value);const minutos=Math.round((value-horas)*100);return (horas*60)+minutos;}function runTool(){const entrada=parseFloat(document.getElementById('ht-entrada').value);const saida=parseFloat(document.getElementById('ht-saida').value);const intervalo=parseFloat(document.getElementById('ht-intervalo').value);clearError();if(isNaN(entrada)||isNaN(saida)||isNaN(intervalo)||intervalo<0){showError('Preencha entrada, saída e intervalo com valores válidos.');return;}const total=toMinutes(saida)-toMinutes(entrada)-(intervalo*60);if(total<=0){showError('A jornada líquida precisa ser maior que zero.');return;}document.getElementById('ht-horas').textContent=fmtNum(total/60,2)+' h';document.getElementById('ht-minutos').textContent=fmtNum(total,0)+' min';document.getElementById('tool-detail').textContent='O cálculo desconta o intervalo da diferença entre entrada e saída.';showResult('tool-result');}function clearTool(){['ht-entrada','ht-saida','ht-intervalo'].forEach(id=>document.getElementById(id).value='');['ht-horas','ht-minutos'].forEach(id=>document.getElementById(id).textContent='-');document.getElementById('tool-detail').textContent='';document.getElementById('tool-result').classList.remove('show');clearError();}function copyTool(button){if(!document.getElementById('tool-result').classList.contains('show')){showError('Calcule as horas antes de copiar o resultado.');return;}copyToClipboard('Horas trabalhadas: '+document.getElementById('ht-horas').textContent,button);}
</script>
